+    {
+        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
+        "in", "on", "at", "to", "for", "of", "with", "by", "from", "it",
+        "this", "that", "these", "those", "be", "been", "being", "have",
+        "has", "had", "do", "does", "did", "will", "would", "could",
+        "should", "may", "might", "shall", "can", "not", "no", "as", "if",
+        "its", "he", "she", "they", "we", "you", "i", "me", "my", "your",
+        "his", "her", "our", "their", "also", "so", "than", "then", "each",
+        "which", "who", "whom", "what", "there", "when", "where", "how",
+        "all", "both", "few", "more", "most", "other", "some", "such",
+        "about", "up", "out", "into", "over", "after", "before", "between"
+    };
